import{_ as a,o as i,c as t,ag as s}from"./chunks/framework.BtjAF3GT.js";const h=JSON.parse('{"title":"Workspace Reference","description":"","frontmatter":{},"headers":[],"relativePath":"workspace-reference.md","filePath":"workspace-reference.md","lastUpdated":1775380040000}'),n={name:"workspace-reference.md"};function l(o,e,r,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="workspace-reference" tabindex="-1">Workspace Reference <a class="header-anchor" href="#workspace-reference" aria-label="Permalink to &quot;Workspace Reference&quot;">​</a></h1><p>The CS Code workspace is organized like a modern SaaS product: one shell, several focused surfaces, and a fast route-to-execution loop.</p><h2 id="navigation-model" tabindex="-1">Navigation model <a class="header-anchor" href="#navigation-model" aria-label="Permalink to &quot;Navigation model&quot;">​</a></h2><p>Primary sections:</p><ul><li>Studio</li><li>Teams</li><li>Billing</li><li>Ops</li><li>Settings</li></ul><p>The sidebar also anchors the conversation list, so routing sessions behave like resumable workspaces instead of isolated prompts.</p><h2 id="studio" tabindex="-1">Studio <a class="header-anchor" href="#studio" aria-label="Permalink to &quot;Studio&quot;">​</a></h2><p>Studio is the main product surface.</p><p>Use it to:</p><ul><li>route requests before execution</li><li>send prompts directly to the chosen model</li><li>inspect fallback options and cost estimates</li><li>continue the same thread across model switches</li><li>attach outcome feedback for later routing optimization</li></ul><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Sidebar[Sidebar\\nThreads + Navigation] --&gt; StudioMain[Studio Composer\\nPrompt + Task + Budget]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	StudioMain --&gt; RouteDecision[Route Decision\\nChosen + Fallbacks]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	RouteDecision --&gt; Execute[Execution Result\\nOutput + Attempt Log]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Execute --&gt; Feedback[Outcome Feedback\\nUseful or Needs Work]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Feedback --&gt; Sidebar</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	StudioMain --&gt; Inspector[Inspector\\nModels + Spend + Memory]</span></span></code></pre></div><h3 id="what-appears-in-the-studio-side-panel" tabindex="-1">What appears in the Studio side panel <a class="header-anchor" href="#what-appears-in-the-studio-side-panel" aria-label="Permalink to &quot;What appears in the Studio side panel&quot;">​</a></h3><ul><li>highlighted models</li><li>request and spend summary</li><li>current route details</li><li>memory context used for the latest decision</li><li>execution feedback controls when a response has completed</li></ul><h2 id="persistent-conversations" tabindex="-1">Persistent conversations <a class="header-anchor" href="#persistent-conversations" aria-label="Permalink to &quot;Persistent conversations&quot;">​</a></h2><p>Conversations are stored server-side per user and tenant.</p><p>That means:</p><ul><li>switching models does not reset context</li><li>re-opening a thread restores the same routing flow</li><li>memory summaries and retrieved turns can be passed into later route and execute requests</li><li>the latest execution can be rated as useful or needing work</li></ul><h2 id="teams" tabindex="-1">Teams <a class="header-anchor" href="#teams" aria-label="Permalink to &quot;Teams&quot;">​</a></h2><p>Teams groups work by collaboration scope and ownership.</p><p>Supported flows:</p><ul><li>create a team</li><li>add members</li><li>send invites</li><li>review pending invites</li></ul><h2 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h2><p>Billing provides:</p><ul><li>current subscription state</li><li>included usage and remaining allowance</li><li>invoice line items</li><li>CSV export</li><li>Stripe checkout and portal entry points</li></ul><h2 id="ops" tabindex="-1">Ops <a class="header-anchor" href="#ops" aria-label="Permalink to &quot;Ops&quot;">​</a></h2><p>Ops is the policies and activity surface.</p><p>Use it to manage:</p><ul><li>routing guardrails</li><li>spend alerts</li><li>webhook endpoints and secret rotation</li><li>webhook deliveries and retries</li><li>notifications and recent activity context</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Settings is user-scoped.</p><p>Current controls include:</p><ul><li>appearance mode</li><li>default landing section</li></ul><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="./model-routing">model-routing.md</a></li><li><a href="./security-features">security-features.md</a></li><li><a href="./api-reference">api-reference.md</a></li></ul>`,34)])])}const m=a(n,[["render",l]]);export{h as __pageData,m as default};
